import React, { useCallback } from "react";
import { View, StyleSheet, Pressable, FlatList, Platform } from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { useHeaderHeight } from "@react-navigation/elements";
import { Feather } from "@expo/vector-icons";
import Animated, { FadeIn } from "react-native-reanimated";
import * as Haptics from "expo-haptics";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { formatDistanceToNow } from "date-fns";
import { ru, enUS } from "date-fns/locale";

import { ThemedText } from "@/components/ThemedText";
import { ThemedView } from "@/components/ThemedView";
import { Avatar } from "@/components/Avatar";
import { VerifiedBadge } from "@/components/VerifiedBadge";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/contexts/AuthContext";
import { apiRequest } from "@/lib/query-client";
import { Spacing, BorderRadius } from "@/constants/theme";
import type { NativeStackScreenProps } from "@react-navigation/native-stack";
import type { RootStackParamList } from "@/navigation/RootStackNavigator";

interface Notification {
  id: string;
  userId: string;
  type: string;
  fromUserId: string | null;
  postId: string | null;
  chatId: string | null;
  isRead: boolean;
  createdAt: string;
  fromUser?: {
    id: string;
    username: string;
    emoji: string;
    isVerified?: boolean;
  };
}

function NotificationItem({
  notification,
  onPress,
  language,
}: {
  notification: Notification;
  onPress: () => void;
  language: string;
}) {
  const { theme } = useTheme();

  const t = (en: string, ru: string) => (language === "ru" ? ru : en);

  const getNotificationIcon = (): keyof typeof Feather.glyphMap => {
    switch (notification.type) {
      case "like":
        return "heart";
      case "comment":
        return "message-square";
      case "message":
        return "message-circle";
      default:
        return "bell";
    }
  };

  const getNotificationText = () => {
    switch (notification.type) {
      case "like":
        return t("liked your post", "оценил ваш пост");
      case "comment":
        return t("commented on your post", "прокомментировал ваш пост");
      case "message":
        return t("sent you a message", "отправил вам сообщение");
      default:
        return t("notification", "уведомление");
    }
  };

  return (
    <Animated.View entering={FadeIn}>
      <Pressable
        onPress={() => {
          Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
          onPress();
        }}
        style={({ pressed }) => [
          styles.notificationItem,
          {
            backgroundColor: pressed
              ? theme.backgroundSecondary
              : notification.isRead
              ? theme.backgroundRoot
              : theme.backgroundDefault,
          },
        ]}
      >
        {notification.fromUser ? (
          <Avatar emoji={notification.fromUser.emoji} size={44} />
        ) : (
          <View
            style={[
              styles.iconContainer,
              { backgroundColor: theme.backgroundSecondary },
            ]}
          >
            <Feather
              name={getNotificationIcon()}
              size={20}
              color={
                notification.type === "like"
                  ? theme.error
                  : notification.type === "comment"
                  ? theme.link
                  : theme.text
              }
            />
          </View>
        )}
        <View style={styles.notificationContent}>
          <View style={{ flexDirection: "row", alignItems: "center", flexWrap: "wrap" }}>
            <ThemedText type="body" style={{ fontWeight: "600" }} truncate maxLength={12}>
              {notification.fromUser?.username || t("Someone", "Кто-то")}
            </ThemedText>
            {notification.fromUser?.isVerified ? <VerifiedBadge size={14} style={{ marginLeft: 4, marginRight: 4 }} /> : null}
            <ThemedText type="body">{getNotificationText()}</ThemedText>
          </View>
          <ThemedText type="caption" style={{ color: theme.textSecondary }}>
            {formatDistanceToNow(new Date(notification.createdAt), { 
              addSuffix: true, 
              locale: language === "ru" ? ru : enUS 
            })}
          </ThemedText>
        </View>
        {!notification.isRead ? (
          <View style={[styles.unreadDot, { backgroundColor: theme.link }]} />
        ) : null}
      </Pressable>
    </Animated.View>
  );
}

function EmptyNotifications() {
  const { theme } = useTheme();

  return (
    <View style={styles.emptyContainer}>
      <Feather name="bell-off" size={64} color={theme.textSecondary} />
      <ThemedText type="h3" style={styles.emptyTitle}>
        No Notifications
      </ThemedText>
      <ThemedText
        type="body"
        style={[styles.emptyText, { color: theme.textSecondary }]}
      >
        You're all caught up!
      </ThemedText>
    </View>
  );
}

type Props = NativeStackScreenProps<RootStackParamList, "Notifications">;

export default function NotificationsScreen({ navigation }: Props) {
  const { theme, language } = useTheme();
  const { user } = useAuth();
  const insets = useSafeAreaInsets();
  const headerHeight = useHeaderHeight();
  const queryClient = useQueryClient();

  const t = (en: string, ru: string) => (language === "ru" ? ru : en);

  const { data: notifications = [] } = useQuery<Notification[]>({
    queryKey: ["/api/users", user?.id, "notifications"],
    enabled: !!user?.id,
  });

  const markReadMutation = useMutation({
    mutationFn: async (notificationId: string) => {
      await apiRequest("POST", `/api/notifications/${notificationId}/read`, {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/users", user?.id, "notifications"] });
    },
  });

  const markAllReadMutation = useMutation({
    mutationFn: async () => {
      await apiRequest("POST", `/api/users/${user?.id}/notifications/read-all`, {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/users", user?.id, "notifications"] });
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
    },
  });

  const handleNotificationPress = (notification: Notification) => {
    if (!notification.isRead) {
      markReadMutation.mutate(notification.id);
    }

    if (notification.type === "message" && notification.chatId) {
      navigation.navigate("Chat", { 
        chatId: notification.chatId,
        otherUserId: notification.fromUser?.id,
        otherUserName: notification.fromUser?.username,
        otherUserEmoji: notification.fromUser?.emoji,
        otherUserUsername: notification.fromUser?.username,
      });
    } else if (notification.postId) {
      navigation.navigate("PostDetail", { postId: notification.postId });
    }
  };

  const unreadCount = notifications.filter((n) => !n.isRead).length;

  const renderItem = useCallback(
    ({ item }: { item: Notification }) => (
      <NotificationItem
        notification={item}
        onPress={() => handleNotificationPress(item)}
        language={language}
      />
    ),
    [handleNotificationPress, language]
  );

  return (
    <ThemedView style={styles.container}>
      <View style={[styles.header, { paddingTop: Platform.OS === 'ios' ? insets.top - 10 : Spacing.md }]}>
        <Pressable onPress={() => navigation.goBack()} hitSlop={8}>
          <Feather name="x" size={24} color={theme.text} />
        </Pressable>
        <ThemedText type="h3">{t("Notifications", "Уведомления")}</ThemedText>
        {unreadCount > 0 ? (
          <Pressable
            onPress={() => markAllReadMutation.mutate()}
            hitSlop={8}
          >
            <ThemedText type="link" style={{ fontSize: 14 }}>{t("Read all", "Все")}</ThemedText>
          </Pressable>
        ) : (
          <View style={{ width: 24 }} />
        )}
      </View>
      <FlatList
        data={notifications}
        renderItem={renderItem}
        keyExtractor={(item) => item.id}
        contentContainerStyle={{
          paddingTop: Spacing.sm,
          paddingBottom: insets.bottom + Spacing.xl,
        }}
        ListEmptyComponent={
          <View style={styles.emptyContainer}>
            <Feather name="bell-off" size={64} color={theme.textSecondary} />
            <ThemedText type="h3" style={styles.emptyTitle}>
              {t("No Notifications", "Нет уведомлений")}
            </ThemedText>
            <ThemedText
              type="body"
              style={[styles.emptyText, { color: theme.textSecondary }]}
            >
              {t("You're all caught up!", "У вас нет новых уведомлений!")}
            </ThemedText>
          </View>
        }
      />
    </ThemedView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  header: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    paddingHorizontal: Spacing.md,
    paddingBottom: Spacing.md,
  },
  notificationItem: {
    flexDirection: "row",
    alignItems: "center",
    paddingHorizontal: Spacing.lg,
    paddingVertical: Spacing.md,
  },
  iconContainer: {
    width: 44,
    height: 44,
    borderRadius: 22,
    alignItems: "center",
    justifyContent: "center",
  },
  notificationContent: {
    flex: 1,
    marginLeft: Spacing.md,
  },
  unreadDot: {
    width: 8,
    height: 8,
    borderRadius: 4,
    marginLeft: Spacing.sm,
  },
  emptyContainer: {
    flex: 1,
    alignItems: "center",
    justifyContent: "center",
    paddingVertical: Spacing["6xl"],
    paddingHorizontal: Spacing.xl,
  },
  emptyTitle: {
    marginTop: Spacing.xl,
    marginBottom: Spacing.sm,
  },
  emptyText: {
    textAlign: "center",
  },
});

