import React, { useState, useCallback, useEffect, useRef } from "react";
import { View, StyleSheet, RefreshControl, Pressable, Dimensions, FlatList, ActivityIndicator } from "react-native";
import { useHeaderHeight } from "@react-navigation/elements";
import { useBottomTabBarHeight } from "@react-navigation/bottom-tabs";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { Image } from "expo-image";
import { Feather } from "@expo/vector-icons";
import Animated, { 
  FadeIn, 
  useAnimatedScrollHandler, 
  useSharedValue, 
  useAnimatedStyle, 
  interpolate,
  Extrapolate,
  withTiming
} from "react-native-reanimated";
import * as Haptics from "expo-haptics";
import * as Clipboard from "expo-clipboard";
import { useQuery, useQueryClient, useMutation } from "@tanstack/react-query";

import { ThemedText } from "@/components/ThemedText";
import { ThemedView } from "@/components/ThemedView";
import { Avatar } from "@/components/Avatar";
import { ParallaxAvatar } from "@/components/ParallaxAvatar";
import { VerifiedBadge } from "@/components/VerifiedBadge";
import { PremiumBadge } from "@/components/PremiumBadge";
import { ProfileEditModal } from "@/components/ProfileEditModal";
import { ProfileEffect, ProfileEffectType } from "@/components/ProfileEffect";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/contexts/AuthContext";
import { getImageUrl, apiRequest } from "@/lib/query-client";
import { storeAuth } from "@/lib/auth";
import { Spacing, BorderRadius } from "@/constants/theme";
import { useRefresh } from "@/contexts/RefreshContext";
import type { NativeStackScreenProps } from "@react-navigation/native-stack";
import type { RootStackParamList } from "@/navigation/RootStackNavigator";
import type { CompositeScreenProps } from "@react-navigation/native";
import type { BottomTabScreenProps } from "@react-navigation/bottom-tabs";
import type { MainTabParamList } from "@/navigation/MainTabNavigator";

const { width: SCREEN_WIDTH } = Dimensions.get("window");
const GRID_GAP = 2;
const NUM_COLUMNS = 3;
const ITEM_SIZE = (SCREEN_WIDTH - GRID_GAP * (NUM_COLUMNS - 1)) / NUM_COLUMNS;

interface Post {
  id: string;
  userId: string;
  imageUrl: string;
  location: string | null;
  createdAt: string;
}

function PostGridItem({ post, onPress }: { post: Post; onPress: () => void }) {
  const { theme } = useTheme();
  const imageUrl = getImageUrl(post.imageUrl);

  return (
    <Pressable onPress={onPress} style={styles.gridItem}>
      {imageUrl ? (
        <Image
          source={{ uri: imageUrl }}
          style={styles.gridImage}
          contentFit="cover"
          transition={100}
        />
      ) : (
        <View style={[styles.gridImage, { backgroundColor: theme.backgroundSecondary, justifyContent: 'center', alignItems: 'center' }]}>
          <Feather name="image" size={24} color={theme.textSecondary} />
        </View>
      )}
    </Pressable>
  );
}

function SkeletonItem() {
  const { theme } = useTheme();
  return (
    <View style={[styles.gridItem, { backgroundColor: theme.backgroundSecondary }]} />
  );
}

function PostsSkeleton() {
  return (
    <View style={styles.skeletonGrid}>
      {[...Array(6)].map((_, i) => (
        <SkeletonItem key={i} />
      ))}
    </View>
  );
}

function EmptyPosts() {
  const { theme } = useTheme();

  return (
    <View style={styles.emptyContainer}>
      <Feather name="image" size={36} color={theme.textSecondary} />
      <ThemedText type="body" style={[styles.emptyText, { color: theme.textSecondary }]}>
        No posts yet
      </ThemedText>
    </View>
  );
}

type Props = CompositeScreenProps<
  BottomTabScreenProps<MainTabParamList, "ProfileTab">,
  NativeStackScreenProps<RootStackParamList>
>;

export default function ProfileScreen({ navigation }: Props) {
  const { theme, isDark, language } = useTheme();
  const { user, refreshUser, setUser, sessionId } = useAuth();
  const headerHeight = useHeaderHeight() || 64;
  const tabBarHeight = useBottomTabBarHeight();
  const insets = useSafeAreaInsets();
  const queryClient = useQueryClient();
  const [refreshing, setRefreshing] = useState(false);
  const [editModalVisible, setEditModalVisible] = useState(false);
  const { setProfileRefreshing } = useRefresh();
  const scrollY = useSharedValue(0);
  const refreshOpacity = useSharedValue(0);

  const lastRefreshRef = useRef(0);

  useEffect(() => {
    refreshOpacity.value = withTiming(refreshing ? 1 : 0, { duration: 200 });
  }, [refreshing]);

  useEffect(() => {
    const unsubscribe = navigation.addListener("focus", () => {
      const now = Date.now();
      if (now - lastRefreshRef.current > 5000) {
        lastRefreshRef.current = now;
        refreshUser();
      }
    });
    return unsubscribe;
  }, [navigation, refreshUser]);

  const t = (en: string, ru: string) => (language === "ru" ? ru : en);

  const { data: posts = [], isLoading: postsLoading } = useQuery<Post[]>({
    queryKey: ["/api/users", user?.id, "posts"],
    enabled: !!user?.id,
    staleTime: 1000 * 60 * 10, // 10 minutes
  });

  const onRefresh = useCallback(async () => {
    setRefreshing(true);
    setProfileRefreshing(true);
    await queryClient.invalidateQueries({ queryKey: ["/api/users", user?.id, "posts"] });
    setRefreshing(false);
    setProfileRefreshing(false);
  }, [queryClient, user?.id, setProfileRefreshing]);

  const handleCopyId = async () => {
    if (user?.id) {
      await Clipboard.setStringAsync(user.id);
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
    }
  };

  const handleAvatarLongPress = () => {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    setEditModalVisible(true);
  };

  const handleSaveProfile = async (emoji: string, username: string) => {
    if (!user?.id) throw new Error("Not authenticated");

    const response = await apiRequest("PATCH", `/api/users/${user.id}/profile`, {
      emoji,
      username,
    });

    if (!response.ok) {
      const data = await response.json();
      throw new Error(data.error || "Failed to save profile");
    }

    const updatedUser = await response.json();

    // 1. Update local storage first to be safe
    if (sessionId) {
      await storeAuth(updatedUser, sessionId);
    }

    // 2. Update context state
    setUser(updatedUser);

    // 3. Force query invalidation and refetching
    await queryClient.refetchQueries({ queryKey: ["/api/users", user.id] });
    await queryClient.invalidateQueries({ queryKey: ["/api/posts"] });
    await queryClient.invalidateQueries({ queryKey: ["/api/users", user.id, "posts"] });
  };

  const scrollHandler = useAnimatedScrollHandler({
    onScroll: (event) => {
      scrollY.value = event.contentOffset.y;
    },
  });

  const headerTitleStyle = useAnimatedStyle(() => {
    const scrollOpacity = interpolate(
      scrollY.value,
      [100, 150],
      [1, 0],
      Extrapolate.CLAMP
    );
    return { opacity: scrollOpacity * (1 - refreshOpacity.value) };
  });

  const spinnerStyle = useAnimatedStyle(() => ({
    opacity: refreshOpacity.value,
    position: 'absolute' as const,
  }));

  const emojiStyle = useAnimatedStyle(() => {
    const opacity = interpolate(
      scrollY.value,
      [100, 150],
      [0, 1],
      Extrapolate.CLAMP
    );
    const translateY = interpolate(
      scrollY.value,
      [100, 150],
      [20, 0],
      Extrapolate.CLAMP
    );
    return { 
      opacity,
      transform: [{ translateY }]
    };
  });

  const mainAvatarStyle = useAnimatedStyle(() => {
    const scale = interpolate(
      scrollY.value,
      [-100, 0, 100],
      [1.2, 1, 0.8],
      Extrapolate.CLAMP
    );
    const opacity = interpolate(
      scrollY.value,
      [50, 100],
      [1, 0],
      Extrapolate.CLAMP
    );
    return {
      transform: [{ scale }],
      opacity,
    };
  });

  const renderItem = useCallback(
    ({ item, index }: { item: Post; index: number }) => {
      const column = index % NUM_COLUMNS;
      return (
        <View
          style={{
            marginRight: column < NUM_COLUMNS - 1 ? GRID_GAP : 0,
            marginBottom: GRID_GAP,
          }}
        >
          <PostGridItem
            post={item}
            onPress={() => navigation.navigate("PostDetail", { postId: item.id })}
          />
        </View>
      );
    },
    [navigation]
  );

  const headerComponent = (
    <View style={styles.header}>
      <ProfileEffect effect={(user as any)?.profileEffect as ProfileEffectType} height={200} scrollY={scrollY} />
      <Pressable onLongPress={handleAvatarLongPress} delayLongPress={500}>
        <Animated.View style={[styles.avatarContainer, mainAvatarStyle]}>
          <ParallaxAvatar emoji={user?.emoji || "🐸"} size={80} />
        </Animated.View>
      </Pressable>
