      <Animated.View 
        entering={SlideInDown.duration(400).springify()}
        style={[styles.controls, { paddingBottom: insets.bottom + Spacing.xl }]}
      >
        <View style={styles.controlsRow}>
          <Pressable
            onPress={() => {
              Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
