function BannedScreen() {
  const { logout, user } = useAuth();

  return (
    <View style={[styles.root, { backgroundColor: "#121212", justifyContent: "center", alignItems: "center", padding: Spacing.xl }]}>
      <Avatar emoji={user?.emoji || "🚫"} size={100} />
