function AppContent() {
  const { user, isLoading } = useAuth();
  const [showLoading, setShowLoading] = useState(true);
  const [iconsPreloaded, setIconsPreloaded] = useState(false);

  useEffect(() => {
    const preload = async () => {
      try {
        await Image.prefetch(SETTINGS_ICON_SOURCES);
      } finally {
        setIconsPreloaded(true);
      }
    };
    preload();
  }, []);

  const handleLoadingFinish = useCallback(() => {
    setShowLoading(false);
  }, []);

  const isReady = !isLoading && iconsPreloaded;

  if (user?.isBanned) {
    return <BannedScreen />;
  }

  // Ensure navigation doesn't start until icons are ready to prevent flicker for new users
  if (!iconsPreloaded && showLoading) {
    return (
      <View style={styles.root}>
        <LoadingScreen 
          emoji={user?.emoji || "🐸"} 
          isReady={false} 
          onFinish={handleLoadingFinish} 
        />
      </View>
    );
  }

  return (
    <View style={styles.root}>
      <NavigationContainer>
        <RootStackNavigator />
      </NavigationContainer>
      <StatusBar style="light" />
      {showLoading && (
        <LoadingScreen 
          emoji={user?.emoji || "🐸"} 
          isReady={isReady} 
          onFinish={handleLoadingFinish} 
        />
      )}
    </View>
  );
}

export default function App() {
  return (
    <ThemeProvider>
      <ErrorBoundary>
        <PersistQueryClientProvider 
          client={queryClient} 
          persistOptions={persistOptions}
        >
