                  </KeyboardProvider>
                </GestureHandlerRootView>
              </SafeAreaProvider>
            </RefreshProvider>
          </AuthProvider>
        </PersistQueryClientProvider>
      </ErrorBoundary>
    </ThemeProvider>
  );
}

const styles = StyleSheet.create({
  root: {
    flex: 1,
  },
});

