    },
    {
      key: "calls",
      icon: "phone",
      title: t("Calls", "Звонки"),
      subtitle: t("Incoming call notifications", "Уведомления о входящих звонках"),
    },
  ];

  return (
    <ThemedView style={styles.container}>
