interface Post {
  id: string;
  imageUrl: string;
}

export default function ArchiveScreen({ navigation }: Props) {
  const { theme, language } = useTheme();
  const { user } = useAuth();
  const insets = useSafeAreaInsets();
  const queryClient = useQueryClient();

  const t = (en: string, ru: string) => (language === "ru" ? ru : en);

  React.useLayoutEffect(() => {
    navigation.setOptions({
      headerTitle: t("Archive", "Архив"),
      headerLeft: () => (
        <Pressable 
          onPress={() => navigation.goBack()}
          hitSlop={20}
          style={{ 
            width: 32,
            height: 32,
            alignItems: "center",
            justifyContent: "center",
            marginLeft: 0,
          }}
        >
          <Feather name="chevron-left" size={28} color={theme.text} />
        </Pressable>
      ),
    });
  }, [navigation, theme.text, language]);

  const { data: archivedPosts, isLoading } = useQuery<Post[]>({
    queryKey: ["/api/users", user?.id, "archived"],
    enabled: !!user?.id,
    staleTime: 0,
  });

  const unarchiveMutation = useMutation({
    mutationFn: async (postId: string) => {
      await apiRequest("DELETE", `/api/users/${user?.id}/archived/${postId}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/posts"] });
      queryClient.invalidateQueries({ queryKey: ["/api/users", user?.id, "posts"] });
      queryClient.invalidateQueries({ queryKey: ["/api/users", user?.id, "archived"] });
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
    },
  });

  const renderItem = ({ item }: { item: Post }) => (
    <Pressable
      onPress={() => navigation.navigate("PostDetail", { postId: item.id })}
      style={styles.item}
    >
      <Image source={{ uri: getImageUrl(item.imageUrl) }} style={styles.image} />
      <View style={styles.unarchiveOverlay}>
        <Pressable
          onPress={(e) => {
            e.stopPropagation();
            Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
            unarchiveMutation.mutate(item.id);
          }}
          style={styles.unarchiveIcon}
        >
          <Feather name="arrow-up" size={18} color="#FFF" />
        </Pressable>
      </View>
    </Pressable>
  );

  if (isLoading) {
    return (
      <ThemedView style={styles.center}>
        <ThemedText>Loading...</ThemedText>
      </ThemedView>
    );
  }

  return (
    <ThemedView style={styles.container}>
      <FlatList
        data={archivedPosts}
        renderItem={renderItem}
        keyExtractor={(item) => item.id}
        numColumns={COLUMN_COUNT}
        contentContainerStyle={{
          paddingBottom: insets.bottom + Spacing.xl,
        }}
        ListEmptyComponent={
          <View style={styles.empty}>
            <Feather name="archive" size={48} color={theme.textSecondary} style={{ marginBottom: Spacing.md }} />
            <ThemedText type="body" style={{ color: theme.textSecondary, textAlign: 'center' }}>
              Your archive is empty.{"\n"}Your hidden memories will be stored here.
            </ThemedText>
          </View>
        }
      />
    </ThemedView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  center: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
  },
  item: {
    width: ITEM_SIZE,
    height: ITEM_SIZE,
    padding: 1,
  },
  image: {
    flex: 1,
  },
  unarchiveOverlay: {
    position: 'absolute',
    top: 6,
    right: 6,
  },
  unarchiveIcon: {
    width: 28,
    height: 28,
    borderRadius: 14,
    backgroundColor: 'rgba(0,0,0,0.5)',
    alignItems: 'center',
    justifyContent: 'center',
  },
  empty: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
    paddingTop: 100,
    paddingHorizontal: Spacing.xl,
  }
});

