export type ThemeKey = 'forest' | 'feldgrau' | 'wheat' | 'midnight' | 'mint' | 'merlot' | 'apricot';

export interface Theme {
  key: ThemeKey;
  name: string;
  colors: {
    primary: string;
    primaryLight: string;
    primaryDark: string;
    accent: string;
    accentDark: string;
    text: string;
    textSecondary: string;
    background: string;
    card: string;
    border: string;
  };
}

export const themes: Record<ThemeKey, Theme> = {
  forest: {
    key: 'forest',
    name: 'Forest',
    colors: {
      primary: '#064734',
      primaryLight: '#0A5C45',
      primaryDark: '#043325',
      accent: '#E8D5B7',
      accentDark: '#D4C5A8',
      text: '#F5F2ED',
      textSecondary: 'rgba(245, 242, 237, 0.6)',
      background: '#064734',
      card: '#0A5C45',
      border: 'rgba(245, 242, 237, 0.1)',
    },
  },
  midnight: {
    key: 'midnight',
    name: 'Midnight Fjord',
    colors: {
      primary: '#053264',
      primaryLight: '#0A4A8A',
      primaryDark: '#031E3D',
      accent: '#FFD482',
      accentDark: '#E6BD6E',
      text: '#F5F2ED',
      textSecondary: 'rgba(245, 242, 237, 0.6)',
      background: '#053264',
      card: '#0A4A8A',
      border: 'rgba(245, 242, 237, 0.1)',
    },
  },
  feldgrau: {
    key: 'feldgrau',
    name: 'Feldgrau',
    colors: {
      primary: '#4D5D53',
      primaryLight: '#5D6D63',
