import { createServer } from "http";
import express, { type Request, Response, NextFunction } from "express";
import { storage } from "./storage";
import { insertPostSchema, insertCommentSchema, insertMessageSchema, insertChatSchema, insertChatSettingsSchema, insertReportSchema, insertPushTokenSchema, insertMiniAppSchema, chats, groupChatMembers, messages, users } from "@shared/schema";
import { db } from "./db";
import { eq, and, isNotNull, desc, like, or, sql, inArray } from "drizzle-orm";
import { z } from "zod";
import { moderateUsername } from "./moderation";
import * as fs from "fs";
import * as path from "path";
import { randomUUID } from "crypto";
import { sendNewMessageNotification, sendLikeNotification, sendCommentNotification, sendCallNotification } from "./push-notifications";

const EMOJIS = ["🐸", "🦊", "🐻", "🐼", "🦁", "🐯", "🐨", "🐮", "🐷", "🐵", "🐔", "🐧", "🐦", "🦆", "🦅", "🦉", "🦇", "🐺", "🐗", "🐴", "🦄", "🐝", "🐛", "🦋", "🐌", "🐞", "🐜", "🦟", "🦗", "🕷", "🦂", "🐢", "🐍", "🦎", "🦖", "🦕", "🐙", "🦑", "🦐", "🦞", "🦀", "🐡", "🐠", "🐟", "🐬", "🐳", "🐋", "🦈", "🐊", "🐅", "🐆", "🦓", "🦍", "🦧", "🐘", "🦛", "🦏", "🐪", "🐫", "🦒", "🦘", "🐃", "🐂", "🐄", "🐎", "🐖", "🐏", "🐑", "🦙", "🐐", "🦌", "🐕", "🐩", "🦮", "🐕‍🦺", "🐈", "🐈‍⬛", "🐓", "🦃", "🦚", "🦜", "🦢", "🦩", "🕊", "🐇", "🦝", "🦨", "🦡", "🦫", "🦦", "🦥", "🐁", "🐀", "🐿", "🦔"];

function sanitizeString(input: string | undefined | null): string | null {
  if (input === undefined || input === null) return null as any;
  if (input === "") return "";
  return input
    .replace(/[<>]/g, "")
    .replace(/javascript:/gi, "")
    .replace(/on\w+\s*=/gi, "")
    .trim()
    .slice(0, 5000);
}

export async function registerRoutes(app: express.Express) {
  // Auth routes
  app.post("/api/auth/register", async (req, res) => {
    try {
      const { username: rawUsername, pin } = req.body;
      const username = sanitizeString(rawUsername);

      if (!username || !pin) {
        return res.status(400).json({ error: "Username and PIN required" });
      }

      if (pin.length !== 4 || !/^\d{4}$/.test(pin)) {
        return res.status(400).json({ error: "PIN must be 4 digits" });
      }

      // Moderate username for offensive content
      const moderationResult = await moderateUsername(username);
      if (!moderationResult.isAllowed) {
        return res.status(400).json({ 
          error: moderationResult.reason || "This username is not allowed" 
        });
      }

      const existingUser = await storage.getUserByUsername(username);
      if (existingUser) {
        return res.status(400).json({ error: "Username already taken" });
      }

      const emoji = EMOJIS[Math.floor(Math.random() * EMOJIS.length)];
      const user = await storage.createUser({ username, pin, emoji });

      const session = await storage.createSession({
        userId: user.id,
        deviceInfo: req.headers["user-agent"] || "Unknown device",
      });

      res.json({ user: { id: user.id, username: user.username, emoji: user.emoji, isVerified: user.isVerified, isAdmin: user.isAdmin, isBanned: user.isBanned, profileEffect: user.profileEffect, isPremium: user.isPremium, usernameColor: user.usernameColor }, session });
    } catch (error) {
      console.error("Register error:", error);
      res.status(500).json({ error: "Failed to register" });
    }
  });

  app.post("/api/auth/login", async (req, res) => {
    try {
      const { userId, pin } = req.body;

      if (!userId || !pin) {
        return res.status(400).json({ error: "User ID and PIN required" });
      }

      let user = await storage.getUserByIdAndPin(userId, pin);

      if (!user) {
        const userByUsername = await storage.getUserByUsername(userId.trim());
        if (userByUsername) {
          user = await storage.getUserByIdAndPin(userByUsername.id, pin);
        }
      }
      if (!user) {
        return res.status(401).json({ error: "Invalid credentials" });
      }

      if (user.isBanned) {
        return res.status(403).json({ error: "Your account is banned" });
      }

      await storage.updateUserLastSeen(user.id);

      const session = await storage.createSession({
        userId: user.id,
        deviceInfo: req.headers["user-agent"] || "Unknown device",
      });

      res.json({ user: { id: user.id, username: user.username, emoji: user.emoji, isVerified: user.isVerified, isAdmin: user.isAdmin, isBanned: user.isBanned, profileEffect: user.profileEffect, isPremium: user.isPremium, usernameColor: user.usernameColor }, session });
    } catch (error) {
      console.error("Login error:", error);
      res.status(500).json({ error: "Failed to login" });
    }
  });

  app.post("/api/auth/logout", async (req, res) => {
    try {
      const { sessionId } = req.body;
      if (sessionId) {
        await storage.deleteSession(sessionId);
      }
      res.json({ success: true });
    } catch (error) {
      console.error("Logout error:", error);
      res.status(500).json({ error: "Failed to logout" });
    }
  });

  app.get("/api/users/:id/sessions", async (req, res) => {
    try {
      const sessions = await storage.getUserSessions(req.params.id);
      res.json(sessions);
    } catch (error) {
      console.error("Get sessions error:", error);
      res.status(500).json({ error: "Failed to get sessions" });
    }
  });

  // Image upload endpoint
  app.post("/api/upload", async (req, res) => {
    try {
      const { image } = req.body;

      if (!image) {
        return res.status(400).json({ error: "No image data provided" });
      }

      // Extract base64 data (handle both raw base64 and data URL formats)
      let base64Data = image;
      let extension = "jpg";

      if (image.startsWith("data:")) {
        const matches = image.match(/^data:image\/(\w+);base64,(.+)$/);
        if (matches) {
          extension = matches[1] === "jpeg" ? "jpg" : matches[1];
          base64Data = matches[2];
        }
      }

      const fileName = `${randomUUID()}.${extension}`;
      const uploadsDir = path.resolve(process.cwd(), "uploads");

      // Ensure uploads directory exists
      if (!fs.existsSync(uploadsDir)) {
        fs.mkdirSync(uploadsDir, { recursive: true });
      }

      const filePath = path.join(uploadsDir, fileName);

      // Write file
      fs.writeFileSync(filePath, Buffer.from(base64Data, "base64"));

      // Return relative path - client will build full URL using EXPO_PUBLIC_DOMAIN
      const relativePath = `/uploads/${fileName}`;

      res.json({ url: relativePath });
    } catch (error) {
      console.error("Upload error:", error);
      res.status(500).json({ error: "Failed to upload image" });
    }
  });

  app.delete("/api/sessions/:id", async (req, res) => {
    try {
      await storage.deleteSession(req.params.id);
      res.json({ success: true });
    } catch (error) {
      console.error("Delete session error:", error);
      res.status(500).json({ error: "Failed to delete session" });
    }
  });

  app.get("/api/users/:id/posts", async (req, res) => {
    try {
      const allPosts = await storage.getUserPosts(req.params.id);
      const archivedIds = await storage.getArchivedPosts(req.params.id);
      const posts = allPosts.filter(post => !archivedIds.includes(post.id));
      const postsWithUser = await Promise.all(posts.map(async (post) => {
        const user = await storage.getUser(post.userId);
        const likesCount = await storage.getPostLikesCount(post.id);
        const commentsCount = await storage.getPostCommentsCount(post.id);
        const currentUserId = req.headers["x-user-id"] as string;
        const isLiked = currentUserId ? !!(await storage.getLike(currentUserId, post.id)) : false;
        const isSaved = currentUserId ? (await storage.getUserSaves(currentUserId)).some(s => s.postId === post.id) : false;

        return {
          ...post,
          user: user ? { id: user.id, username: user.username, emoji: user.emoji, isVerified: user.isVerified, isPremium: user.isPremium, usernameColor: user.usernameColor } : undefined,
          likesCount,
          commentsCount,
          isLiked,
          isSaved
        };
      }));
      res.json(postsWithUser);
    } catch (error) {
      console.error("Get user posts error:", error);
      res.status(500).json({ error: "Failed to get user posts" });
    }
  });

  // Users routes
  app.get("/api/users/by-username/:username", async (req, res) => {
    try {
      const user = await storage.getUserByUsername(req.params.username);
      if (!user) return res.status(404).json({ error: "User not found" });
      res.json({ id: user.id, username: user.username, emoji: user.emoji, isVerified: user.isVerified, isAdmin: user.isAdmin, isBanned: user.isBanned, profileEffect: user.profileEffect, isPremium: user.isPremium, usernameColor: user.usernameColor });
    } catch (error) {
      console.error("Get user by username error:", error);
      res.status(500).json({ error: "Failed to get user" });
    }
  });

  app.get("/api/users/search", async (req, res) => {
    try {
      const query = req.query.q as string;
      if (!query) return res.json([]);
      const results = await storage.searchUsers(query);
      res.json(results.map(u => ({ id: u.id, username: u.username, emoji: u.emoji, isVerified: u.isVerified, isPremium: u.isPremium, usernameColor: u.usernameColor })));
    } catch (error) {
      console.error("Search users error:", error);
      res.status(500).json({ error: "Failed to search users" });
    }
  });

  app.get("/api/users/:id", async (req, res) => {
    try {
      const user = await storage.getUser(req.params.id);
      if (!user) return res.status(404).json({ error: "User not found" });
      res.json({ id: user.id, username: user.username, emoji: user.emoji, isVerified: user.isVerified, isAdmin: user.isAdmin, isBanned: user.isBanned, lastUsernameChange: user.lastUsernameChange, profileEffect: user.profileEffect, isPremium: user.isPremium, usernameColor: user.usernameColor });
    } catch (error) {
      console.error("Get user error:", error);
      res.status(500).json({ error: "Failed to get user" });
    }
  });

  app.patch("/api/users/:id/profile", async (req, res) => {
    try {
      const { emoji, username } = req.body;
      const userId = req.params.id;

      const user = await storage.getUser(userId);
      if (!user) {
        return res.status(404).json({ error: "User not found" });
      }

      if (!emoji) {
        return res.status(400).json({ error: "Emoji is required" });
      }

      let usernameToUpdate: string | undefined;

      if (username && username !== user.username) {
        if (!user.isAdmin) {
          if (user.lastUsernameChange) {
            const lastChange = new Date(user.lastUsernameChange);
            const now = new Date();
            const daysSinceChange = Math.floor((now.getTime() - lastChange.getTime()) / (1000 * 60 * 60 * 24));
            if (daysSinceChange < 20) {
              const daysLeft = 20 - daysSinceChange;
              return res.status(400).json({ 
                error: `You can change your username in ${daysLeft} days` 
              });
            }
          }
        }

        if (username.length < 2 || username.length > 20) {
          return res.status(400).json({ error: "Username must be 2-20 characters" });
        }

        const existingUser = await storage.getUserByUsername(username);
        if (existingUser && existingUser.id !== userId) {
          return res.status(400).json({ error: "Username already taken" });
        }

        const moderationResult = await moderateUsername(username);
        if (!moderationResult.isAllowed) {
          return res.status(400).json({ 
            error: moderationResult.reason || "This username is not allowed" 
          });
        }

        usernameToUpdate = username;
      }

      const updated = await storage.updateUserProfile(userId, emoji, usernameToUpdate);

      res.json({ 
        id: updated.id, 
        username: updated.username, 
        emoji: updated.emoji, 
        isVerified: updated.isVerified, 
        isAdmin: updated.isAdmin, 
        isBanned: updated.isBanned,
        lastUsernameChange: updated.lastUsernameChange,
        profileEffect: updated.profileEffect
      });
    } catch (error) {
      console.error("Update profile error:", error);
      res.status(500).json({ error: "Failed to update profile" });
    }
  });

  app.patch("/api/users/:id/profile-effect", async (req, res) => {
    try {
      const { effect } = req.body;
      const userId = req.params.id;
      const validEffects = [null, "stars", "rain", "aurora", "fireflies", "sakura", "nebula"];
      if (!validEffects.includes(effect)) {
        return res.status(400).json({ error: "Invalid effect" });
      }

      if (effect !== null) {
        const user = await storage.getUser(userId);
        if (!user?.isPremium && !user?.isAdmin) {
          return res.status(403).json({ error: "Premium subscription required for profile effects" });
        }
      }

      const [updated] = await db.update(users).set({ profileEffect: effect }).where(eq(users.id, userId)).returning();
      if (!updated) {
        return res.status(404).json({ error: "User not found" });
      }
      res.json({ profileEffect: updated.profileEffect });
    } catch (error) {
      console.error("Update profile effect error:", error);
      res.status(500).json({ error: "Failed to update effect" });
    }
  });

  app.patch("/api/users/:id/username-color", async (req, res) => {
    try {
      const userId = req.params.id;
      const { color } = req.body;

      const user = await storage.getUser(userId);
      if (!user) return res.status(404).json({ error: "User not found" });
      if (!user.isPremium && !user.isAdmin) return res.status(403).json({ error: "Premium subscription required" });

      if (color !== null && !/^#[0-9A-Fa-f]{6}$/.test(color)) {
        return res.status(400).json({ error: "Invalid color" });
      }

      const [updated] = await db.update(users).set({ usernameColor: color }).where(eq(users.id, userId)).returning();
      res.json({ usernameColor: updated.usernameColor, isPremium: updated.isPremium });
    } catch (error) {
      console.error("Update username color error:", error);
      res.status(500).json({ error: "Failed to update color" });
    }
  });

  // Posts routes
  app.get("/api/posts", async (req, res) => {
    try {
      const limit = Math.min(parseInt(req.query.limit as string) || 10, 50);
      const offset = parseInt(req.query.offset as string) || 0;
      const currentUserId = req.headers["x-user-id"] as string;

      const postsWithData = await db.execute(sql`
        SELECT 
          p.*,
          u.id as author_id, u.username as author_username, u.emoji as author_emoji, u.is_verified as author_verified, u.is_premium as author_premium, u.username_color as author_username_color,
          COALESCE(lc.likes_count, 0)::int as likes_count,
          COALESCE(cc.comments_count, 0)::int as comments_count,
          ${currentUserId ? sql`CASE WHEN ul.user_id IS NOT NULL THEN true ELSE false END` : sql`false`} as is_liked,
          ${currentUserId ? sql`CASE WHEN us.user_id IS NOT NULL THEN true ELSE false END` : sql`false`} as is_saved
        FROM posts p
        LEFT JOIN users u ON u.id = p.user_id
        LEFT JOIN (SELECT post_id, COUNT(*) as likes_count FROM likes GROUP BY post_id) lc ON lc.post_id = p.id
        LEFT JOIN (SELECT post_id, COUNT(*) as comments_count FROM comments GROUP BY post_id) cc ON cc.post_id = p.id
        ${currentUserId ? sql`LEFT JOIN likes ul ON ul.post_id = p.id AND ul.user_id = ${currentUserId}` : sql``}
        ${currentUserId ? sql`LEFT JOIN saves us ON us.post_id = p.id AND us.user_id = ${currentUserId}` : sql``}
        LEFT JOIN archived_posts ap ON ap.post_id = p.id AND ap.user_id = p.user_id
        WHERE ap.id IS NULL
        ORDER BY p.created_at DESC
        LIMIT ${limit} OFFSET ${offset}
      `);

      const result = postsWithData.rows.map((row: any) => ({
        id: row.id,
        userId: row.user_id,
        imageUrl: row.image_url,
        caption: row.caption,
        location: row.location,
        latitude: row.latitude,
        longitude: row.longitude,
        feeling: row.feeling,
        createdAt: row.created_at,
        user: row.author_id ? {
          id: row.author_id,
          username: row.author_username,
          emoji: row.author_emoji,
          isVerified: row.author_verified,
          isPremium: row.author_premium === true || row.author_premium === 't',
          usernameColor: row.author_username_color,
        } : undefined,
        likesCount: row.likes_count,
        commentsCount: row.comments_count,
        isLiked: row.is_liked === true || row.is_liked === 't',
        isSaved: row.is_saved === true || row.is_saved === 't',
      }));

      res.json(result);
    } catch (error) {
      console.error("Get posts error:", error);
      res.status(500).json({ error: "Failed to get posts" });
    }
  });

  app.post("/api/posts", async (req, res) => {
    try {
      const postData = insertPostSchema.parse(req.body);
      const post = await storage.createPost(postData);
      res.json(post);
    } catch (error) {
      console.error("Create post error:", error);
      res.status(400).json({ error: "Invalid post data" });
    }
  });

  app.get("/api/posts/:id", async (req, res) => {
    try {
      const post = await storage.getPost(req.params.id);
      if (!post) return res.status(404).json({ error: "Post not found" });

      const user = await storage.getUser(post.userId);
      const likesCount = await storage.getPostLikesCount(post.id);
      const commentsCount = await storage.getPostCommentsCount(post.id);
      const currentUserId = req.headers["x-user-id"] as string;
      const isLiked = currentUserId ? !!(await storage.getLike(currentUserId, post.id)) : false;
      const isSaved = currentUserId ? !!(await storage.getSave(currentUserId, post.id)) : false;

      res.json({
        ...post,
        user: user ? { id: user.id, username: user.username, emoji: user.emoji, isVerified: user.isVerified } : undefined,
        likesCount,
        commentsCount,
        isLiked,
        isSaved
      });
    } catch (error) {
      console.error("Get post error:", error);
      res.status(500).json({ error: "Failed to get post" });
    }
  });

  app.patch("/api/posts/:id", async (req, res) => {
    try {
      const { caption, location, feeling, latitude, longitude, imageUrl, userId } = req.body;
      const post = await storage.getPost(req.params.id);

      if (!post) {
        return res.status(404).json({ error: "Post not found" });
      }

      if (post.userId !== userId) {
        return res.status(403).json({ error: "Unauthorized" });
      }

      const updatedPost = await storage.updatePost(req.params.id, { 
        caption, 
        location, 
        feeling,
        latitude: latitude?.toString(), 
        longitude: longitude?.toString(),
        imageUrl 
      });
      res.json(updatedPost);
    } catch (error) {
      console.error("Update post error:", error);
      res.status(500).json({ error: "Failed to update post" });
    }
  });

  app.delete("/api/posts/:id", async (req, res) => {
    try {
      await storage.deletePost(req.params.id);
      res.json({ success: true });
    } catch (error) {
      console.error("Delete post error:", error);
      res.status(500).json({ error: "Failed to delete post" });
    }
  });

  // Likes routes
  app.post("/api/posts/:id/like", async (req, res) => {
    try {
      const userId = req.body.userId;
      if (!userId) return res.status(400).json({ error: "User ID required" });

      const existing = await storage.getLike(userId, req.params.id);
      if (existing) {
        await storage.deleteLike(userId, req.params.id);
        res.json({ liked: false });
      } else {
        await storage.createLike({ userId, postId: req.params.id });

        // Send push notification for new like
        const post = await storage.getPost(req.params.id);
        const liker = await storage.getUser(userId);
        if (post && liker && post.userId !== userId) {
          sendLikeNotification(post.userId, liker.username, liker.emoji, post.id);
        }

        res.json({ liked: true });
      }
    } catch (error) {
      console.error("Like post error:", error);
      res.status(500).json({ error: "Failed to like post" });
    }
  });

  // Saves routes
  app.get("/api/users/:id/saves", async (req, res) => {
    try {
      const saves = await storage.getUserSaves(req.params.id);
