  app.get("/api/stripe/products", async (_req, res) => {
    try {
      const result = await db.execute(sql`
        SELECT 
          p.id as product_id,
          p.name as product_name,
          p.description as product_description,
          p.metadata as product_metadata,
          pr.id as price_id,
          pr.unit_amount,
          pr.currency,
          pr.recurring,
          pr.active as price_active
        FROM stripe.products p
        LEFT JOIN stripe.prices pr ON pr.product = p.id AND pr.active = true
        WHERE p.active = true
        ORDER BY p.name, pr.unit_amount
      `);

      const productsMap = new Map();
      for (const row of result.rows as any[]) {
        if (!productsMap.has(row.product_id)) {
          productsMap.set(row.product_id, {
            id: row.product_id,
            name: row.product_name,
            description: row.product_description,
            metadata: row.product_metadata,
            prices: [],
          });
        }
        if (row.price_id) {
          productsMap.get(row.product_id).prices.push({
            id: row.price_id,
            unitAmount: row.unit_amount,
            currency: row.currency,
            recurring: row.recurring,
          });
        }
      }

      res.json({ products: Array.from(productsMap.values()) });
    } catch (error) {
      console.error("List products error:", error);
      res.json({ products: [] });
    }
  });

  app.post("/api/stripe/checkout", async (req, res) => {
    try {
      const { userId, priceId } = req.body;
      if (!userId || !priceId) {
        return res.status(400).json({ error: "userId and priceId required" });
      }

      const user = await storage.getUser(userId);
      if (!user) {
        return res.status(404).json({ error: "User not found" });
      }

      const { getUncachableStripeClient } = await import("./stripeClient");
      const stripe = await getUncachableStripeClient();

      let customerId = user.stripeCustomerId;
      if (customerId) {
        try {
          await stripe.customers.retrieve(customerId);
        } catch (e: any) {
          if (e?.code === 'resource_missing') {
            customerId = null;
          } else {
            throw e;
          }
        }
      }
      if (!customerId) {
        const customer = await stripe.customers.create({
          metadata: { userId: user.id, username: user.username },
        });
        customerId = customer.id;
        await db.update(users).set({ stripeCustomerId: customerId }).where(eq(users.id, userId));
      }

      const baseUrl = `https://${process.env.REPLIT_DOMAINS?.split(',')[0]}`;
      const session = await stripe.checkout.sessions.create({
        customer: customerId,
        payment_method_types: ['card'],
        line_items: [{
          price_data: {
            currency: 'usd',
            product_data: {
              name: 'Okeno Premium',
              description: 'Premium subscription with exclusive features',
            },
            unit_amount: 499,
            recurring: {
              interval: 'month',
            },
          },
          quantity: 1,
        }],
        mode: 'subscription',
        success_url: `${baseUrl}/checkout/success?session_id={CHECKOUT_SESSION_ID}`,
        cancel_url: `${baseUrl}/checkout/cancel`,
        metadata: { userId: user.id },
      });

      res.json({ url: session.url });
    } catch (error) {
      console.error("Checkout error:", error);
      res.status(500).json({ error: "Failed to create checkout session" });
    }
  });

  app.get("/api/stripe/subscription/:userId", async (req, res) => {
    try {
      const user = await storage.getUser(req.params.userId);
      if (!user) {
        return res.status(404).json({ error: "User not found" });
      }
      res.json({ isPremium: user.isPremium, stripeCustomerId: user.stripeCustomerId });
    } catch (error) {
      console.error("Get subscription error:", error);
      res.status(500).json({ error: "Failed to get subscription" });
    }
  });

  app.post("/api/stripe/portal", async (req, res) => {
    try {
      const { userId } = req.body;
      if (!userId) return res.status(400).json({ error: "userId required" });

      const user = await storage.getUser(userId);
      if (!user || !user.stripeCustomerId) {
        return res.status(404).json({ error: "No subscription found" });
      }

      const { getUncachableStripeClient } = await import("./stripeClient");
      const stripe = await getUncachableStripeClient();

      const baseUrl = `https://${process.env.REPLIT_DOMAINS?.split(',')[0]}`;
      const portalSession = await stripe.billingPortal.sessions.create({
        customer: user.stripeCustomerId,
        return_url: baseUrl,
      });

      res.json({ url: portalSession.url });
    } catch (error) {
      console.error("Portal error:", error);
      res.status(500).json({ error: "Failed to create portal session" });
    }
  });

  app.post("/api/stripe/verify-session", async (req, res) => {
    try {
      const { sessionId, userId } = req.body;
      if (!sessionId || !userId) return res.status(400).json({ error: "sessionId and userId required" });

      const { getUncachableStripeClient } = await import("./stripeClient");
      const stripe = await getUncachableStripeClient();

      const session = await stripe.checkout.sessions.retrieve(sessionId);
      if (session.payment_status === "paid" && session.status === "complete") {
        await db.update(users).set({ isPremium: true }).where(eq(users.id, userId));
        const updatedUser = await storage.getUser(userId);
        res.json({ success: true, user: updatedUser });
      } else {
        res.json({ success: false, status: session.status });
      }
    } catch (error) {
      console.error("Verify session error:", error);
      res.status(500).json({ error: "Failed to verify session" });
    }
  });

  app.get("/api/premium/features", (_req, res) => {
    res.setHeader('Cache-Control', 'public, max-age=3600');
    res.json({
      features: [
        { id: "effects", titleEn: "Profile Effects", titleRu: "Эффекты профиля", descEn: "Exclusive animated effects for your profile", descRu: "Эксклюзивные анимированные эффекты для профиля", icon: "star" },
        { id: "badge", titleEn: "Premium Badge", titleRu: "Премиум значок", descEn: "Stand out with a special badge on your profile", descRu: "Выделяйтесь особым значком на профиле", icon: "award" },
        { id: "themes", titleEn: "Exclusive Themes", titleRu: "Эксклюзивные темы", descEn: "Access to unique color themes", descRu: "Доступ к уникальным цветовым темам", icon: "droplet" },
        { id: "upload", titleEn: "HD Uploads", titleRu: "HD загрузки", descEn: "Upload photos in full resolution", descRu: "Загружайте фото в полном разрешении", icon: "upload-cloud" },
        { id: "name", titleEn: "Custom Username Colors", titleRu: "Цвет имени", descEn: "Choose a color for your username", descRu: "Выберите цвет для вашего имени", icon: "edit-3" },
        { id: "priority", titleEn: "Priority Support", titleRu: "Приоритетная поддержка", descEn: "Get help faster from our support team", descRu: "Получайте помощь быстрее от команды поддержки", icon: "zap" },
      ],
    });
  });

  app.get("/checkout/success", async (req, res) => {
    const sessionId = req.query.session_id as string;
    let activated = false;

    if (sessionId) {
      try {
        const { getUncachableStripeClient } = await import("./stripeClient");
        const stripe = await getUncachableStripeClient();
        const session = await stripe.checkout.sessions.retrieve(sessionId);
        if (session.payment_status === "paid" && session.metadata?.userId) {
          await db.update(users).set({ 
            isPremium: true,
            stripeCustomerId: session.customer as string
          }).where(eq(users.id, session.metadata.userId));
          activated = true;
        }
      } catch (e: any) {
        console.error("[Checkout Success] Error:", e?.message);
      }
    }

    res.send(`<!DOCTYPE html>
<html lang="ru">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Okeno Premium</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'SF Pro', sans-serif; background: #0a0a0a; color: #fff; display: flex; align-items: center; justify-content: center; min-height: 100vh; padding: 20px; }
    .card { text-align: center; max-width: 400px; }
    .icon { font-size: 64px; margin-bottom: 16px; }
    h1 { font-size: 28px; font-weight: 700; margin-bottom: 8px; }
    p { font-size: 16px; color: #999; line-height: 1.5; margin-bottom: 24px; }
    .btn { display: inline-block; background: #FFD700; color: #000; padding: 14px 32px; border-radius: 12px; text-decoration: none; font-weight: 600; font-size: 16px; }
  </style>
</head>
<body>
  <div class="card">
    <div class="icon">${activated ? "✅" : "⏳"}</div>
    <h1>${activated ? "Премиум активирован!" : "Оплата получена!"}</h1>
    <p>${activated ? "Спасибо за покупку! Теперь вам доступны все премиум-функции. Вернитесь в приложение." : "Ваш платёж обрабатывается. Премиум будет активирован в течение минуты. Вернитесь в приложение."}</p>
    <a class="btn" href="okeno://premium">Вернуться в приложение</a>
  </div>
</body>
</html>`);
  });

  app.get("/checkout/cancel", (_req, res) => {
    res.send(`<!DOCTYPE html>
